    params: {
      fetchPolicy: 'reload_revalidating_cache_data' // Загрузка с сервера, фолбэк на кэш
    }
  });
  console.log('Default audience onboarding fetched successfully');
} catch (error) {
  console.error('Failed to fetch default audience onboarding:', error);
}
```

